INSERT INTO `wp_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES
(1, 1, 'Bir WordPress yorumcusu', 'wapuu@wordpress.example', 'https://tr.wordpress.org/', '', '2026-04-09 03:23:39', '2026-04-09 00:23:39', 'Merhaba, bu bir yorumdur.\nYorum yönetimine başlamak, düzenlemek ve silmek için lütfen Başlangıç ekranındaki yorumlar bölümüne gidin.\nYorumcuların avatarları <a href=\"https://gravatar.com/\">Gravatar</a> üzerinden alınır.', 0, 'post-trashed', '', 'comment', 0, 0);
