(103, 1, '2026-04-10 19:14:38', '2026-04-10 16:14:38', '<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1.Hazırlık</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#1haz%C4%B1rl%C4%B1k\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.1 Neden Front-End Framework\'leri Var?✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#11-neden-front-end-frameworkleri-var\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.2 React vs. Vanilla JavaScript✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#12-react-vs-vanilla-javascript\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.3 React Nedir?✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#13-react-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.4 Geliştirme Ortamı✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#14-geli%C5%9Ftirme-ortam%C4%B1\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">1.5 Resmi Dokümantasyon✅</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#15-resmi-dok%C3%BCmantasyon\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Bileşenler ve JSX</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#2-bile%C5%9Fenler-ve-jsx\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.1 Bileşenler⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#21-bile%C5%9Fenler\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.2 JSX Nedir?⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#22-jsx-nedir\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.3 JSX Kuralları⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#23-jsx-kurallar%C4%B1\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.4 Props Mantığı⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#24-props-mant%C4%B1%C4%9F%C4%B1\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.5 Prop Destructuring⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#25-prop-destructuring\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":4} -->\n<h4 class=\"wp-block-heading\">2.6 Fragments⌛</h4>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#26-fragments\"></a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3.State ve \"Thinking in React\"</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><a href=\"https://github.com/ardaozdogan0/react.js/tree/main?tab=readme-ov-file#3state-ve-thinking-in-react\"></a></p>\n